  // lib/repositories/sessionsRepository.ts
  async function createSessionRepo(workspaceId, userId, createdBy) {
    const sessionRef = doc(collection(db, "sessions"));
    const workspaceRef = doc(db, "workspaces", workspaceId);
    const sessionData = {
      workspaceId,
      userId,
      title: "Untitled Session",
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp(),
      createdBy: createdBy ?? null,
      viewCount: 0,
      commentCount: 0,
      openCount: 0,
      resolvedCount: 0,
      feedbackCount: 0
    };
    await runTransaction(db, async (tx) => {
      tx.set(sessionRef, sessionData);
      tx.update(workspaceRef, {
        "usage.sessionsCreated": increment(1),
        updatedAt: serverTimestamp()
      });
    });
    return sessionRef.id;
  }
  async function getWorkspaceSessionCountRepo(workspaceId) {
    const baseQuery = query(
      collection(db, "sessions"),
      where("workspaceId", "==", workspaceId)
    );
    const [allSnap, archivedSnap] = await Promise.all([
      getCountFromServer(baseQuery),
      getCountFromServer(
        query(
          collection(db, "sessions"),
          where("workspaceId", "==", workspaceId),
          where("archived", "==", true)
        )
      )
    ]);
    const total = allSnap.data().count;
    const archived = archivedSnap.data().count;
    return Math.max(0, total - archived);
  }
  async function getWorkspaceSessionsRepo(workspaceId, max = 50, archivedOnly, includeArchived) {
    assertQueryLimit(max, "getWorkspaceSessionsRepo");
    const q2 = query(
      collection(db, "sessions"),
      where("workspaceId", "==", workspaceId),
      ...archivedOnly === true ? [where("archived", "==", true)] : [],
      orderBy("updatedAt", "desc"),
      limit(max)
    );
    const snapshot = await getDocs(q2);
    return snapshot.docs.filter((docSnap) => {
      if (includeArchived) return true;
      const archived = docSnap.data().archived === true;
      return archivedOnly ? archived : !archived;
    }).map((docSnap) => ({
      id: docSnap.id,
      ...docSnap.data()
    }));
  }
